import {create} from 'zustand';

export const useStore = create(() => ({
 catalog: [{
  id:'243089jw',
  name: 'Hose',
  price: 21.99
 },{
  id:'r489243nz',
  name: 'Hemd',
  price: 19.50
 }]
}));

import {useStore} from "../store/index.js";

const Catalog = () => {
 const data = useStore((state) => state.catalog);
 return (
  &lt;>
   { data.map(item => &lt;>
    &lt;div key={item.id}>
     {item.name} &lt;span>{item.price} €&lt;/span>
    &lt;/div>
   &lt;/>)}
  &lt;/>
 )
}

export default Catalog;

import {create} from 'zustand';

export const useStore = create((set) => ({
 catalog: [{
  id:'243089jw',
  name: 'Hose',
  price: 21.99
 },{
  id:'r489243nz',
  name: 'Hemd',
  price: 19.50
 }],

 addToCatalog: (payload) => set((state) => ({
  catalog: [...state.catalog, payload] // Füge das neue Produkt zum Array hinzu
 }))

}));

import {useStore} from "../store/index.js";

const Catalog = () => {
 const data = useStore((state) => state.catalog);
 const addToCatalog = useStore((state) => state.addToCatalog);
 const addProduct = () => {
  addToCatalog({
   id: (Math.random() * 1e17).toString(36) ,
   name: 'Mütze',
   price: +(Math.random()*25+5).toFixed(2)
  })
 }

 return (
  &lt;>
   &lt;h2>Katalog&lt;/h2>
   {
    data.map(item => &lt;>
     &lt;div key={item.id}>
      {item.name} &lt;span>{item.price} €&lt;/span>
     &lt;/div>
    &lt;/>)
   }
   &lt;button onClick={addProduct}>Add Product&lt;/button>
  &lt;/>
 )
}

export default Catalog;

import {create} from 'zustand';

export const useStore = create((set, get) => ({
 catalog: [{
  id:'243089jw',
  name: 'Hose',
  price: 21.99
 },{
  id:'r489243nz',
  name: 'Hemd',
  price: 19.50
 }],

 getCheaperThen: (maxPrice) => {
  const { catalog } = get();
  return catalog.filter((p) => p.price < maxPrice);
 },
}));

import {useStore} from "../store/index.js";
import {useState} from "react";

const Catalog = () => {
 const [threshold, setThreshold] = useState(20);
 const getCheaperThen = useStore((state)=> state.getCheaperThen)

 return (
  &lt;>
   &lt;h2>Katalog&lt;/h2>
   {
    getCheaperThen(threshold).map(item => &lt;>
     &lt;div key={item.id}>
      {item.name} &lt;span>{item.price} €&lt;/span>
     &lt;/div>
    &lt;/>)
   }
   &lt;input value={threshold} onChange={evt => setThreshold(+evt.target.value)}/>
  &lt;/>
 )
}

export default Catalog;
